export default "html[data-webmcp-page-edit-config] [data-measuring=true] {\n  cursor: crosshair;\n}\n\nhtml[data-webmcp-page-edit-config] body:not([testing]) [data-selected=true] {\n  transition: all 0.15s ease;\n}\n\nhtml[data-webmcp-page-edit-config] [data-pseudo-select=true] {\n  outline: 1px dashed hsl(267 100% 58%);\n}\n\nhtml[data-webmcp-page-edit-config] [data-selected-hide=true][data-selected=true]::after {\n  display: none;\n}\n\nhtml[data-webmcp-page-edit-config] [data-selected=true][contenteditable=true] {\n  caret-color: hotpink;\n}\n\nhtml[data-webmcp-page-edit-config] [data-pinhover=true] {\n  cursor: crosshair;\n}\n\nhtml[data-webmcp-page-edit-config] [data-metatip=true][data-pinhover=true] {\n  cursor: not-allowed;\n}\n\nhtml[data-webmcp-page-edit-config] [draggable=true] {\n  cursor: grab;\n}\n\nhtml[data-webmcp-page-edit-config] [draggable=true]:active {\n  cursor: grabbing;\n}\n\nhtml[data-webmcp-page-edit-config] [draggable=true] a,\nhtml[data-webmcp-page-edit-config] [draggable=true] img {\n  -webkit-user-drag: none !important;\n}\n";
